var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"그리고 마지막 주의사항으로…","JPN":"そして最後の注意事項として……","ENG":"And lastly, one final precaution…","TWN":"最後一個注意事項…"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"헌혈이나 수혈은 함부로 하시면 안 됩니다. 혈액이 필요한 경우, 이 팔찌를 차고 계시면 도시관리국에서 도움을 드릴 거예요.","JPN":"献血や輸血は任意で行わないこと。血液が必要な場合、このブレスレットをしていれば都市管理局からサポートがあるはずです。","ENG":"You mustn't give or receive blood carelessly. If you ever need a transfusion, wear this band and the City Management will handle it for you.","TWN":"不要隨便捐血或輸血。如果需要血液，只要戴著這個手環，城市管理局就會協助你。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"저기. 제대로 듣고 계신 거 맞죠?","JPN":"あの、聞いていますか？","ENG":"Hey, are you listening to all this?","TWN":"先生，你有在聽嗎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…듣고 있네.","JPN":"……聞いているとも。","ENG":"…I hear you.","TWN":"…有在聽。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"방금 말한 열 가지 주의사항도 새겨두도록 하지.","JPN":"先程言われた10個の注意事項もしっかり覚えておくとしよう。","ENG":"I shall keep in mind the ten other points you just listed.","TWN":"剛才說的十個注意事項，我也會牢記在心。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"건강에 문제가 있는 것 같으면 언제든 저희 민원 부서로 편하게 연락 주세요.","JPN":"健康に異常を感じましたら、いつでも担当部署にご連絡ください。","ENG":"If you ever feel unwell, please don't hesitate to reach out to our civil office.","TWN":"要是身體有哪裡不舒服，歡迎隨時找我們。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_PATH_M","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"기억 소거의 후유증은 거의 없는 편이라고 하지만, 혹시 모르니까요.","JPN":"記憶消去の後遺症はほぼないと言われていますが、注意して損することはありませんから。","ENG":"There are almost no side effects from memory erasure, but you never know.","TWN":"雖然刪除記憶後沒什麼後遺症，但還是提醒一下。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_PATH_M","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"기억 소거…","JPN":"記憶消去……","ENG":"Memory erasure…","TWN":"刪除記憶…"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"그래. 관리국을 떠나는 조건으로 내 기억을 지우기로 했었지.","JPN":"そうか。管理局を去る条件として、自分の記憶を消すことにしたのであったな。","ENG":"Right. That was the condition for leaving the Administration.","TWN":"沒錯，我離開管理局的條件，就是要刪除我的記憶。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"정확히는 관리국에 근무하실 적의 기억만 사라진 겁니다.","JPN":"正確には、管理局に勤めていた間の記憶だけですね。","ENG":"Technically speaking, only your memories from your time in the Administration are gone.","TWN":"準確地說，只有刪除你在管理局工作時的記憶。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_PATH_M","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"함께 일한 동료의 이름이나 얼굴을 기억하거나 한때 익숙했던 것에 대한 기시감 정도는 느낄 수 있겠지만, 시술에 이상이 있다는 뜻은 아니니 너무 걱정 마시고요.","JPN":"一緒に働いていた同僚の名前や顔を思い出したり、見慣れていたものに対する既視感は残るかもしれませんが、施術に問題があったわけではありませんので、ご心配なく。","ENG":"You may still feel a vague sense of familiarity if you run into an old colleague or something familiar, but that's normal. Nothing to worry about.","TWN":"你可能會記得一起共事過的夥伴名字或臉孔，或是對曾經熟悉的事物產生既視感，但這並不代表手術有問題，所以不用太擔心。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_PATH_M","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"이해했네.","JPN":"理解した。","ENG":"Understood.","TWN":"我明白了。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"현 시간 부로 당신의 신원은 관리국에 귀속되지 않습니다. 퇴사 절차는 끝났어요.","JPN":"現時刻をもって、あなたの身元は管理局の所管外となります。これで退職手続きは完了しました。","ENG":"As of this moment, you are no longer bound to the Administration. Your discharge is complete.","TWN":"從現在起，你的身份不再屬於管理局。離職手續都已經跑完了。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_PATH_M","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"고마웠소. 여러 모로.","JPN":"色々と感謝する。","ENG":"My thanks. For all of it.","TWN":"謝謝你，還提醒我這麼多事。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"감사는 오히려 저희 같은 사람들이 해야죠.","JPN":"感謝するのはむしろ私たちの方です。","ENG":"We're the ones who should thank you.","TWN":"應該謝謝的反而是我們。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"전 내부 사정을 잘 모르는 관외 직원일 뿐이지만…","JPN":"私は内部の事情に詳しくない外部職員ですが……","ENG":"I'm just a staff, so I don't know much about internal matters but…","TWN":"我雖然只是個小員工，不清楚解內部情況…"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"관리실패를 겪고 살아남은 관리국 분들은 모두 존중 받을 만한 분이라 생각하거든요.","JPN":"管理失敗を経験してなお生き残った管理局の方々は、皆尊敬に値する方々だと思っています。","ENG":"I believe anyone who survived the Administration Failure deserves respect.","TWN":"但我認為經歷管理失敗後倖存下來的管理局人員，都值得尊敬。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"관리실패…?","JPN":"管理失敗……？","ENG":"Administration Failure…?","TWN":"管理失敗…？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"아, 제가 쓸데없는 소릴 했네요. 시술 직후엔 복잡한 생각을 피하라고 했는데.","JPN":"あ、余計なことを口走ってしまいましたね。施術直後は複雑なことを考えないようにと言われているのに。","ENG":"Ah, forget I said that. You're not supposed to dwell on anything complicated right after the procedure.","TWN":"抱歉，我在胡說什麼。明明說過手術後要避免複雜的思考。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_PATH_M","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"이건 챔버로 가는 항공 탑승권입니다.","JPN":"こちらチェンバー行きの航空券です。","ENG":"This is your ticket to Chamber.","TWN":"這是前往強巴的機票。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"도착하면 현지 기업의 연구원 분들이 기다리고 계실 거예요.","JPN":"着きましたら、現地企業の研究員の方々が迎えに来ていると思います。","ENG":"Once you arrive, researchers from a local company will be waiting for you.","TWN":"抵達後，會有當地企業的研究員等著你。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"챔버? 고향으로 돌아가는 게 절차가 아니었나? 내가 살던 곳은 그곳이 아닐 텐데.","JPN":"チェンバー？　マニュアルによれば、次は故郷に帰るのではなかったか？　某が住んでいた場所はそこではないはずだが。","ENG":"Chamber? Wasn't I supposed to return home? That's not where I lived.","TWN":"強巴？按照規定不是應該回故鄉嗎？我原本住的地方應該不是那裡。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"맞아요. 당신의 예전 거주지는 현재… KS-7이라 불리는 관리국 관할지로 변했죠.","JPN":"そうですね。あなたの居住地だった場所は現在……KS-7と呼ばれる管理局管轄地になっています。","ENG":"True. Your old home is now… under the Administration's jurisdiction called KS-7.","TWN":"沒錯。你以前居住的地方，現在…稱為KS-7， 是由管理局管轄的地方。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"거긴 평범한 시골이던 과거와 달리, 지금은 사람이 살 수 없는 아주 위험한 침식지대예요.","JPN":"普通の田舎町だった昔と違い、今は人が住めない危険な侵食地帯です。","ENG":"It's no longer the quiet countryside it used to be. It's an uninhabitable, dangerous Corrupted Area now.","TWN":"那裡已經不再是過去的純樸鄉村，現在是個無法居住、非常危險的侵蝕地帶。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"대신 챔버엔 당신 같은 인재를 필요로 하는 기업과 안전한 집이 있거든요.","JPN":"ですが、チェンバーにはあなたのような人材を求めている企業と、安全な住宅があるのです。","ENG":"But Chamber has safe housing and companies that need talent like yours.","TWN":"但強巴有需要你這種人才的企業和安全的家。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…그렇구려.","JPN":"……そうか。","ENG":"…I see.","TWN":"…原來如此。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"안전을 위해 고향은 돌아가지 못하게 된 건가.","JPN":"身の安全のため、故郷には戻れぬようになってしまったのか。","ENG":"So, I can't go back for safety's sake.","TWN":"基於安全的緣故，我不能回到故鄉嗎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"챔버로 가겠소.","JPN":"チェンバーに行こう。","ENG":"Chamber it is, then.","TWN":"我會去強巴。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"고생하셨어요.","JPN":"お疲れ様でした。","ENG":"You've done well.","TWN":"辛苦了。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_PATH_M","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"OFFICER_ADMIN_PATH_M","text":{"KOREA":"그간 관리국에 기여한 당신의 노고에 무구한 감사를 표합니다.","JPN":"今まで管理局にご尽力くださったことに、深く感謝いたします。","ENG":"We're deeply grateful for all you've given the Administration.","TWN":"對於你對管理局的貢獻，我們獻上最誠摯的感謝。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"감사하다는 말은 머리를 훑고 귓전에 맴돌 뿐… 가슴에 와닿진 않더군.","JPN":"感謝という言葉は頭を通り過ぎ、耳元でこだまするだけで……心には響かなかった。","ENG":"Those words of thanks washed over my mind… but never reached my heart.","TWN":"感謝這句話，只是在腦海中盤旋，在耳邊迴盪…無法觸及我的內心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":null,"text":{"KOREA":"당연한 반응이지. 나는 내가 관리국에서 무엇을 했는지도 기억하지 못했으니.","JPN":"当然であろう。某は己が管理局で何をしていたかすらも覚えておらぬゆえ。","ENG":"No surprise. I couldn't even remember what I'd done for them.","TWN":"這是理所當然的反應，我連我在管理局做過什麼都不記得。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"관리국에 속하기 전의 난 과학자 아버지의 연구를 돕던 평범한 아들이었어.","JPN":"管理局に所属する前の某は、科学者である父の研究を手伝う平凡な息子であった。","ENG":"Before the Administration, I was just an ordinary son helping my scientist father with his research.","TWN":"在加入管理局之前，我只是一個平凡的兒子，幫著科學家爸爸做研究。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":null,"text":{"KOREA":"그러다 침식재난을 겪고, 관리국에서 정장을 입은 사람들이 찾아왔지.","JPN":"そんなある日、侵食災害を経験し、管理局から背広を着た者たちがやって来た。","ENG":"Then came the Corruption disaster, and men in suits showed up at my door.","TWN":"經歷侵蝕災難後，管理局那些穿著西裝的人找上門來。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":null,"text":{"KOREA":"아버지의 장례를 마치곤 미련 없이 그자들을 따라 나섰어.","JPN":"父の葬式が終わると、某は何の未練もなく彼らについて行ったのである。","ENG":"I buried my father, and without regret, followed those men away.","TWN":"辦完爸爸的葬禮後，我毫不猶豫地跟他們走了。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"그것이 내가 온전히 간직하고 있는 마지막 기억.","JPN":"ここまでが、某がはっきりと覚えている最後の記憶。","ENG":"That's the last memory I truly kept.","TWN":"這是我唯一完整保留的記憶。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"…그래.","JPN":"……そう。","ENG":"…Yes.","TWN":"…對了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"그렇게 떠날 때까지만 해도 난 내가 겪은 재난이 무엇인지 알지 못했지.","JPN":"そうやって故郷を去るまで、己が経験した災害が何なのかすら理解していなかった。","ENG":"When I left, I still didn't know the name of the disaster that took everything.","TWN":"直到離開時，我還不知道我經歷的災難是什麼。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"하담아! 멈추지 말아라!","JPN":"カタン！　止まるな！","ENG":"Ha Dam! Don't stop!","TWN":"夏垣！不要停！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"숲이 끝날 때까지 뛰어! 뒤돌아볼 생각 말고!","JPN":"森を抜けるまで走れ！　決して後ろを振り返るな！","ENG":"Run! Keep running until you're clear of the forest! Don't you dare look back!","TWN":"跑到森林的盡頭！別回頭！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"허나 지금은 알고 있다네.","JPN":"しかし今なら分かる。","ENG":"But now, I know it well enough.","TWN":"但現在我知道了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"내 옛 시절을 송두리째 앗아간, 그 검은 재앙의 이름을.","JPN":"某の過去を奪い去った、あの黒き災害の名が。","ENG":"The name of the dark disaster that stole my entire past.","TWN":"奪走我整個過往時光，那黑色災難的名字是什麼。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EMPLOYEE_NPC_NULL_14","text":{"KOREA":"티켓 확인 도와드리겠습니다.","JPN":"チケットを確認させていただきます。","ENG":"I'll check your ticket.","TWN":"請出示機票。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EMPLOYEE_NPC_NULL_14","text":{"KOREA":"챔버로 가시는군요.","JPN":"チェンバー行きのお客様ですね。","ENG":"Headed to Chamber, I see.","TWN":"是去強巴嗎。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"EMPLOYEE_NPC_NULL_14","text":{"KOREA":"여행의 목적은?","JPN":"旅の目的を教えていただけますか？","ENG":"Purpose of your trip?","TWN":"旅行的目的是？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"관리국에서 지낼 곳과 직장을 마련해주었소. 당분간 그곳에서 머무를 예정일세.","JPN":"管理局が住居と職場を用意してくれた。しばらくはそこに滞在する予定である。","ENG":"The Administration arranged work and housing for me. I plan to stay there for the time being.","TWN":"管理局為我安排了住處和工作，我暫時會待在那裡。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EMPLOYEE_NPC_NULL_14","text":{"KOREA":"얼마나 체류할 예정이시죠?","JPN":"滞在期間はどれくらいのご予定ですか？","ENG":"How long do you plan to stay?","TWN":"預計停留多久？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"나에겐 이제 돌아갈 곳이 없어.","JPN":"某には帰る場所がないのでな。","ENG":"I have no place left to return to.","TWN":"我已經沒有回頭路。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"떠날 일이 없다면 떠날 계획도 없는 법이니. 계속 거기에 남겠지.","JPN":"去ることがなければ、去る計画もまたない。そのままそこに留まるであろう。","ENG":"If I've nowhere to leave for, then I suppose I shall simply remain.","TWN":"既然沒有離開的打算，那我就會一直留在那裡。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EMPLOYEE_NPC_NULL_14","text":{"KOREA":"평생 과거를 잊은 채로, 살아갈 셈인가요?","JPN":"一生過去を忘れたまま生きていくおつもりですか？","ENG":"So you'll live your whole life like this? Forgetting the past?","TWN":"你打算一輩子都忘記過去活著嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EMPLOYEE_NPC_NULL_14","text":{"KOREA":"기억을 지운다는 건 정말 편리하네요. 우릴 잊고 도망치는 걸로 끝났다고 생각하다니.","JPN":"記憶を消すというのはとても便利ですね。私たちのことなんて忘れて、逃げてしまえば済むと思うだなんて。","ENG":"Wiping memories really is convenient. Just run away and pretend you've left us behind.","TWN":"刪除記憶還真方便呢。你以為忘記我們逃離這裡，事情就結束了嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"그것 참 가시 박힌 말이로군.","JPN":"ずいぶんと刺のある言い方をする。","ENG":"That's a barbed thing to say.","TWN":"這問題好尖銳。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"그대는 무슨 연유로 날 자극하는 거요?","JPN":"そなたは何故に某を刺激する？","ENG":"What is it you hope to gain, poking at me like this?","TWN":"你為何要刺激我？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"TWISTED_NPC_NULL_14","text":{"KOREA":"아직도 모르겠어? 과거를 버린 당신은 영원히 행복할 수 없다는걸.","JPN":"まだ分からないの？　過去を捨てたあなたは、永遠に幸せにはなれないわ。","ENG":"Still don't get it? A man who abandons his past can never truly be happy.","TWN":"你還不明白嗎？拋棄過去的你是永遠不會幸福的。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"TWISTED_NPC_NULL_14","text":{"KOREA":"그러니까 도망치지 말고 기억해내.","JPN":"だから逃げないで、思い出して。","ENG":"So stop running and remember.","TWN":"所以不要逃避，去想起來。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"TWISTED_NPC_NULL_14","text":{"KOREA":"당신의 진짜 이름… 당신의 과거를…","JPN":"あなたの本当の名前……あなたの過去を……","ENG":"Your true name… Your past…","TWN":"你真正的名字…你的過去…"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GIRL_NPC_NURSERY_NULL","text":{"KOREA":"으음… 선생니임…","JPN":"うーん……せんせい……","ENG":"Mmm… Mr. Seosaeng…","TWN":"嗯…老師…"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GIRL_NPC_NURSERY_NULL","text":{"KOREA":"좀만 더 잘래애…","JPN":"もうちょっと寝るう……","ENG":"Just five more minutes…","TWN":"我再睡一下下…"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L37_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"아이들 낮잠 시간에 나까지 잠든 건가.","JPN":"子どもと共に昼寝をしてしまったか。","ENG":"Did I doze off with the children?","TWN":"我是在孩子們午睡時一起睡著了嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"그럼, 베일은 아직도 회사에…","JPN":"ということは、ベイルはまだ会社に……","ENG":"Then Vale must still be working…","TWN":"那，培麗還在公司…"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…경보음?","JPN":"……警報？","ENG":"…An alert?","TWN":"…警報聲？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ABBESS_NPC_NULL_14","text":{"KOREA":"다들 일어나렴! 얼른 움직여야 해!","JPN":"みんな起きて！　早く移動しないと！","ENG":"Wake up, everyone! We need to move, now!","TWN":"大家快起來！不要再睡了！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NUN_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"NUN_NPC_NULL_14","text":{"KOREA":"서생 씨도 저희랑 같이 대피해요!","JPN":"ショウさんも私たちと一緒に避難しましょう！","ENG":"Dr. Seosaeng, please come with us. We have to evacuate!","TWN":"書生也跟我們一起去避難吧！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NUN_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"NUN_NPC_NULL_14","text":{"KOREA":"침식재난사태입니다! 지금 도심 내부에서부터 계속 확산되고 있대요!","JPN":"侵食災害事態です！　今、都心内部から拡大中らしくて！","ENG":"It's a Corruption Disaster! It's spreading through the city center!","TWN":"是侵蝕災難！聽說正從市中心持續往外圍擴散！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":null,"text":{"KOREA":"약 1시간 전, 서니베일 일대에서 국지성 침식현상 코드 BR-D가 발생했습니다.","JPN":"約1時間前、サニーベイル一帯から局地的侵食現象、コードBR-Dが発生しました。","ENG":"Roughly one hour ago, localized Counterside Effect code BR-D was confirmed over Sunnyvale.","TWN":"大約在1小時前，陽光谷一帶發生局部侵蝕現象，代號BR-D。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"해당 코드가 챔버에서 발생한 것은 이번이 처음입니다.","JPN":"当該コードがチェンバーで発生したのは今回が初めてです。","ENG":"This is the first time Chamber has seen a BR-D event.","TWN":"這是強巴首次出現這種代號。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"BR-D 침식구름 현상이 동반하는 소나기는 먹비라 불리는 위험성 높은 액체로, 땅에 침식 쐐기를 자라게 할 뿐 아니라 접촉을 통해 일반인의 세포조직에 돌이킬 수 없는 손상을 일으키는 것으로 알려졌습니다.","JPN":"BR-D侵食雲現象に伴うにわか雨は、墨雨と呼ばれる非常に危険な液体です。地面に侵食楔を発生させるだけでなく、一般人が接触すると細胞組織に回復不可能な損傷を引き起こすとされています。","ENG":"The BR-D Corruption Cloud brings a rain called Ink Rain, a highly hazardous liquid that spawns Corrupted Wedges in the ground and causes irreversible cell damage on contact.","TWN":"BR-D侵蝕雲現象伴隨的陣雨，是一種稱為墨雨的危險液體，不僅會使土地長出侵蝕釘，還會經由接觸對人的細胞組織造成不可逆的損傷。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"해당 재해는 대부분의 물질을 투과하는 성질이 있어, 특수 방공시설의 보호를 받지 못한 인원들의 피해가 지속적으로 …","JPN":"当該災害はほとんどの物質を透過する性質を持っており、特殊防護施設の保護を受けられなかった人員への被害が継続……","ENG":"The disaster can permeate nearly any material. Casualties are expected to continue for those not under special anti-air shelters…","TWN":"由於這場災害具有穿透大部分物質的性質，未受到特殊防空設施保護的人將持續受害…"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L6_1","type":"dialog","speaker":"AGENT_NPC_NULL_14","text":{"KOREA":"여긴 에비뉴 2번가 교량! 방금 전, 인가되지 않은 이륜차 한 대가 경계선을 넘어갔습니다!","JPN":"こちらはアベニュー2番街の橋です！　つい先程、許可されていない二輪車1台が境界線を超えました！","ENG":"This is Avenue 2 Bridge! Just now, an unauthorized motorcycle crossed the perimeter!","TWN":"這裡是林蔭大道2號橋！剛才，有一輛未經授權的摩托車越過警戒線！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L8_1","type":"dialog","speaker":"DEVICE_NPC_NULL_14","text":{"KOREA":"침식오염 의심자가 검문 절차를 어기고 위험구역을 벗어났단 건가요?","JPN":"侵食汚染が疑われる者が、検問手続きを無視して危険区域を離脱したということですか？","ENG":"An infected suspect broke through a checkpoint and escaped the danger zone?","TWN":"意思是疑似受到侵蝕污染的人，沒經過臨檢擅自離開危險區域嗎？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_NPC_NULL_14","text":{"KOREA":"안에서 밖으로 나간 게 아닙니다!","JPN":"いえ、中から外に出たわけではありません！","ENG":"No, the individual didn't escape from inside!","TWN":"不是離開危險區域！"},"stage":{"bg":"MAINSTREAM_000008","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"AGENT_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"AGENT_NPC_NULL_14","text":{"KOREA":"그 사람 스스로 위험구역에 들어갔어요!","JPN":"自ら危険区域に入って行きました！","ENG":"That person rode straight into the danger zone!","TWN":"是自行進入危險區域！"},"stage":{"bg":"MAINSTREAM_000008","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"AGENT_NPC_NULL_14","face":"UNIT_IDLE"}}}}]`);export{e as default};